const body = $json.body ?? $json;
const now = new Date().toISOString();
const inputRoot = 'C:\\ServerCIT\\services\\heal-match-preparation';
const outputRoot = 'C:\\ServerCIT\\services\\heal-variant-enrichment';
function normalizePath(value) { return String(value ?? '').replace(/\//g, '\\'); }
function assertInside(root, target, label) {
  const normalizedRoot = normalizePath(root).toLowerCase();
  const normalizedTarget = normalizePath(target).toLowerCase();
  if (!normalizedTarget.startsWith(normalizedRoot + '\\')) throw new Error(`${label} is outside the allowed root.`);
}
const inputPath = normalizePath(body.inputPath || body.deliverableAuditCsv);
const outputDir = normalizePath(body.outputDir);
const cacheDir = normalizePath(body.cacheDir || `${outputRoot}\\cache`);
const runId = String(body.runId ?? $execution.id);
if (!inputPath || !outputDir) throw new Error('inputPath and outputDir are required.');
assertInside(inputRoot, inputPath, 'inputPath');
assertInside(outputRoot, outputDir, 'outputDir');
assertInside(outputRoot, cacheDir, 'cacheDir');
const payload = { inputPath, outputDir, cacheDir, runId };
const inputJsonBase64 = Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
const command = `powershell -NoProfile -ExecutionPolicy Bypass -File "C:\\ServerCIT\\services\\heal-variant-enrichment\\run_heal_variant_enrichment.ps1" -InputJsonBase64 "${inputJsonBase64}"`;
return [{ json: { accepted: true, event: 'heal.variant_enrichment.requested', runId, inputPath, outputDir, cacheDir, command, receivedAt: now, source: 'heal-api' } }];

const stdout = String($json.stdout ?? '');
const stderr = String($json.stderr ?? '');
const lines = stdout.trim().split(/\r?\n/).filter(Boolean);
const lastLine = lines[lines.length - 1] ?? '{}';
let summary;
try { summary = JSON.parse(lastLine); }
catch (error) { throw new Error(`Variant enrichment returned invalid JSON: ${error.message}. stderr=${stderr}`); }
return [{ json: { accepted: summary.status === 'valid' || summary.status === 'warning', event: 'heal.variant_enrichment.completed', runId: $('Prepare Variant Enrichment').first().json.runId, status: summary.status, summary, completedAt: new Date().toISOString(), n8n: { workflowName: 'HEAL - Variant Enrichment', executionId: $execution.id } } }];
